1	'use strict';
2	// E-253 (v23.0) — THE BREACH ADJUDICATION GATE.
3	//
4	// THE PROBLEM THIS EXISTS TO SOLVE, stated plainly:
5	//   Every breach Tamazia has ever sent to a client was a REGULAR EXPRESSION matched against crawled HTML, and NO
6	//   MODEL EVER LOOKED AT IT. The LLM classified the sector, discovered new laws, and cross-checked which frameworks
7	//   attach. It never once read an evidence quote, never saw a finding, and never judged whether a regex hit was
8	//   actually a breach of the obligation it claimed to breach.
9	//
10	//   That is why a bare-word regex accused a criminal-defence law firm of being hacked: it matched "sex
11	//   discrimination", the HTML <slot> element, and "pornography offences", and called it injected spam.
12	//
13	//   The LLM gate (src/lib/llm/gate.js) is good. It was simply POINTED AT THE WRONG LAYER. It verified WHICH LAWS
14	//   ATTACH. It never verified WHETHER THEY WERE BROKEN.
15	//
16	// WHAT THIS DOES:
17	//   Regex proposes. The model adjudicates. Only adjudicated breaches ship.
18	//   For each candidate finding the model is given the obligation, the statutory citation, the verbatim evidence (or
19	//   the absence evidence), the page it was found on, and nothing else. It answers ONE question:
20	//   does this evidence establish this breach? BREACH / NO_BREACH / INSUFFICIENT.
21	//
22	// SAFETY CONTRACT (this is why it cannot break anything):
23	//   * The adjudicator is a FILTER. It may only REMOVE or DOWNGRADE a finding. It can NEVER invent one.
24	//   * If the LLM is unavailable, or the gate scores below threshold three times, NOTHING IS REMOVED. The engine
25	//     behaves exactly as it does today. No regression is possible.
26	//   * BUT: a finding that was never adjudicated AND is HIGH-RISK (a P0, or a `prohibit`-type rule, which is the
27	//     class that fabricates) is demoted to NEEDS_REVIEW rather than shipped as a confirmed breach. So even with
28	//     every LLM provider down, the porn/slot class can never reach a client again.
29	//
30	// TOKEN COST: findings are batched (10 per call, evidence truncated). A UK law firm produces ~30 candidates, so
31	// ~3 calls, ~5k tokens per audit. Groq 8B carries 500k tokens/day; Cloudflare Workers AI adds 10k neurons/day on a
32	// SEPARATE quota. Affordable at 200+ mints/day.
33	
34	const BATCH = 10;
35	const VERDICTS = new Set(['breach', 'no_breach', 'insufficient']);
36	
37	// The rule types most prone to false positives. A `prohibit` rule fires when a PATTERN IS PRESENT, which is exactly
38	// how "sex discrimination" became "injected pornography spam". A P0 is the loudest claim we make. Neither may ever
39	// ship unadjudicated.
40	// E-272 — AN OBSERVED FACT IS NOT AN INTERPRETATION, AND THE MODEL MUST NOT BE ASKED TO RULE ON ONE.
41	//
42	// THE BUG THIS KILLS (caught on the live russell-cooke page): the browser watched 11 tracking hosts and a
43	// non-essential cookie fire BEFORE any consent. That is a completed breach of PECR reg.6 — a P0, and the single most
44	// un-arguable finding this engine can produce. The adjudicator then DROPPED it, and the page told the client
45	// "No critical statutory breach surfaced this scan."
46	//
47	// WHY: the adjudicator was built to kill REGEX false positives. Its whole method is to check a QUOTED PASSAGE OF
48	// TEXT against the statute. A cookie observation has no text quote to check — the evidence is a cookie jar and a
49	// network log, which the model cannot see. So the model, correctly following its own rubric, returns
50	// "insufficient" / "no_breach", and our best evidence is suppressed by a judge who was handed no exhibit.
51	//
52	// THE RULE: findings whose evidence is a DIRECT OBSERVATION (a real browser reading the cookie jar) or a PUBLIC
53	// REGISTER lookup (the ICO Register of Data Controllers) are FACTS, not readings of a page. They bypass adjudication
54	// entirely and ship as observed. The adjudicator keeps full authority over every text-derived finding, which is the
55	// only class that ever fabricated anything.
56	const OBSERVED_STATES = new Set(['observed_in_browser', 'public_register_checked']);
57	function _observedFact(f) {
58	  const st = f && f.absence_evidence && f.absence_evidence.state;
59	  return !!(st && OBSERVED_STATES.has(String(st)));
60	}
61	
62	function _highRisk(f) {
63	  if (!f) return false;
64	  if (String(f.severity || '') === 'P0') return true;
65	  if (String(f.rule_type || '') === 'prohibit') return true;
66	  if (/COMPROMISE|SITE_INTEGRITY|SPAM|INJECT/i.test(String(f.code || '') + ' ' + String(f.framework || ''))) return true;
67	  return false;
68	}
69	
70	// Compact, quotable view of ONE finding. Everything the model needs to rule on it and nothing else, so it cannot
71	// read our own confidence off the payload and simply agree with us.
72	// E-255 (v23.1) — STATUTE GROUNDING. statute_chunks holds 908 chunks of REAL STATUTE TEXT across 366 laws, and
73	// statute-rag.js has read them since the day it was written. NO MINT EVER CALLED IT. The adjudicator was about to
74	// judge a breach against OUR OWN PARAPHRASE of the obligation (the `description` column), which means a wrong or
75	// stale description would be laundered into a legal claim with a model's endorsement on it.
76	// It now judges against the ACTUAL WORDS OF THE LAW, retrieved by full-text search over statute_chunks for exactly
77	// the framework being ruled on. This is the difference between "does this look like a breach" and "does this
78	// evidence fail the test the statute actually sets".
79	function _statuteFor(codes) {
80	  let rag = null;
81	  try { rag = require('../compliance/statute-rag.js'); } catch (_e) { return {}; }
82	  const out = {};
83	  for (const code of new Set(codes.filter(Boolean))) {
84	    try {
85	      const hits = rag.retrieve(String(code), { law_id: String(code), k: 2 }) || [];
86	      const text = hits.map((h) => String(h.chunk_text || '').trim()).filter(Boolean).join(' … ').slice(0, 700);
87	      if (text) out[code] = text;
88	    } catch (_e) { /* a missing statute is not a failure: the adjudicator falls back to the obligation text */ }
89	  }
90	  return out;
91	}
92	
93	function _brief(f, i) {
94	  const ev = String(f.evidence_quote || '').trim();
95	  const ae = f.absence_evidence || {};
96	  const absence = !ev
97	    ? (ae.nearest_quote ? ('NEAREST TEXT FOUND ON THE SITE: "' + String(ae.nearest_quote).slice(0, 220) + '"')
98	      : ('CLAIM: the required disclosure is ABSENT. Pages checked: ' + (ae.pages_checked || 0) + '. No page text is shown to you.'))
99	    : null;
100	  return {
101	    id: i,
102	    obligation: String(f.description || '').slice(0, 240),
103	    law: String(f.statutory_citation || f.framework || '').slice(0, 90),
104	    kind: ev ? 'PRESENCE: we matched text on the site and claim it breaches' : 'ABSENCE: we claim a required disclosure is missing',
105	    evidence: ev ? ('VERBATIM FROM THE SITE: "' + ev.slice(0, 300) + '"') : absence,
106	    page: String(f.evidence_url || (Array.isArray(f.checked_urls) ? f.checked_urls[0] : '') || '').slice(0, 120),
107	  };
108	}
109	
110	function _system() {
111	  return 'You are a compliance adjudicator. A regular-expression engine has PROPOSED candidate breaches of law on a '
112	    + 'company website. Your only job is to rule on each one against the evidence given. You are the last check before '
113	    + 'a legal claim is sent to that company. You do not add findings. You do not soften findings. You rule.';
114	}
115	
116	function _prompt(ctx, briefs, statutes) {
117	  const st = statutes && Object.keys(statutes).length
118	    ? ['', 'THE ACTUAL TEXT OF THE LAW (retrieved from the statute corpus — judge against THIS, not against our summary):',
119	       ...Object.entries(statutes).map(([k, v]) => '  [' + k + '] ' + v), '']
120	    : [];
121	  return [
122	    'FIRM: ' + ctx.domain + ' | SECTOR: ' + ctx.sector + ' | COUNTRY: ' + ctx.country,
123	    ...st,
124	    'For EACH candidate below return a verdict:',
125	    '  "breach"       = the evidence, AS GIVEN, establishes a breach of the stated obligation.',
126	    '  "no_breach"    = it does not. Use this for FALSE POSITIVES: the matched text means something else in context',
127	    '                   (a legal practice area, an HTML tag name, a quotation, a negation, a blog post ABOUT the law),',
128	    '                   or the obligation is plainly satisfied by the text shown.',
129	    '  "insufficient" = the evidence is too thin to rule either way. Not a breach. Not a clearance.',
130	    '',
131	    'HARD RULES:',
132	    '  1. Judge ONLY the evidence given. No outside knowledge of this firm. No assumptions about the rest of the site.',
133	    '  2. A FIRM WRITING ABOUT A TOPIC IS NOT COMMITTING IT. "We defend clients accused of X" is never evidence of X.',
134	    '     A page discussing pornography offences, sex discrimination, fraud or money laundering is a PRACTICE AREA.',
135	    '     This is the single most common false positive. Look for it first.',
136	    '  3. HTML and technical vocabulary is not site content. <slot>, <frame>, a script filename: never evidence.',
137	    '  4. For an ABSENCE claim, "no_breach" means the required disclosure IS present in the text you were shown.',
138	    '     If you were shown no page text, you CANNOT clear an absence claim: answer "insufficient".',
139	    '  5. For EVERY "no_breach" you MUST quote, verbatim, the words from the evidence that disprove the claim, in',
140	    '     "disproof". If you cannot quote them, your verdict is "insufficient", not "no_breach".',
141	    '  6. Never invent a citation, a fine, or a finding.',
142	    '',
143	    'CANDIDATES:',
144	    JSON.stringify(briefs),
145	    '',
146	    'Return STRICT JSON only:',
147	    '{"verdicts":[{"id":0,"verdict":"breach|no_breach|insufficient","reason":"<=20 words","disproof":"<verbatim quote from the evidence, or null>"}]}',
148	  ].join('\n');
149	}
150	
151	// DETERMINISTIC RUBRIC. Never the model's self-reported confidence: verbalised confidence is systematically
152	// miscalibrated, while structural validity and verbatim anchoring are not.
153	function _rubric(briefs, batch) {
154	  const byId = new Map(batch.map((f, i) => [i, f]));
155	  return (parsed) => {
156	    const defs = [];
157	    if (!parsed || !Array.isArray(parsed.verdicts)) return { score: 0, deficiencies: ['no "verdicts" array in the JSON'], hard_fail: true };
158	    const v = parsed.verdicts;
159	    let score = 0;
160	
161	    // 3 pts — exactly one verdict per candidate.
162	    const ids = new Set(v.map((x) => Number(x && x.id)));
163	    const complete = briefs.every((b) => ids.has(b.id)) && v.length === briefs.length;
164	    if (complete) score += 3;
165	    else defs.push('return EXACTLY one verdict per candidate id (' + briefs.map((b) => b.id).join(',') + '); you returned ' + v.length);
166	
167	    // 3 pts — every verdict is in the enum.
168	    const enumOk = v.every((x) => VERDICTS.has(String((x && x.verdict) || '').toLowerCase()));
169	    if (enumOk) score += 3;
170	    else defs.push('verdict must be exactly one of: breach, no_breach, insufficient');
171	
172	    // 4 pts — THE ANCHOR, and the whole safety property. Every no_breach must carry a VERBATIM disproof that
173	    // actually appears in the evidence we handed it. Without this a model could clear a real breach by asserting
174	    // it away, which would be far worse than the false positives we are removing.
175	    let anchored = true;
176	    for (const x of v) {
177	      if (String((x && x.verdict) || '').toLowerCase() !== 'no_breach') continue;
178	      const f = byId.get(Number(x.id));
179	      const hay = (String((f && f.evidence_quote) || '') + ' ' + JSON.stringify((f && f.absence_evidence) || {})).toLowerCase();
180	      const q = String((x && x.disproof) || '').toLowerCase().trim().replace(/^["']|["']$/g, '');
181	      if (q.length < 6 || !hay.includes(q.slice(0, 40))) {
182	        anchored = false;
183	        defs.push('id ' + x.id + ': a "no_breach" needs a VERBATIM disproof quoted from the evidence shown. "' + String((x && x.disproof) || '').slice(0, 30) + '" does not appear in it.');
184	      }
185	    }
186	    if (anchored) score += 4;
187	
188	    return { score, deficiencies: defs.slice(0, 6) };
189	  };
190	}
191	
192	/**
193	 * Adjudicate candidate breaches. Returns a NEW findings array; never mutates the input.
194	 * FILTER ONLY: removes false positives, downgrades unprovable claims. It cannot add a finding.
195	 */
196	async function adjudicateBreaches(findings, ctx, opts) {
197	  const out = (findings || []).map((f) => Object.assign({}, f));
198	  if (!out.length) return { findings: out, report: { ran: false, reason: 'no_findings', total: 0 } };
199	  ctx = ctx || {};
200	
201	  let gateLLM = null;
202	  try { ({ gateLLM } = require('../llm/gate.js')); } catch (_e) { gateLLM = null; }
203	
204	  // NO LLM AVAILABLE. Nothing is removed, so there is zero regression against today's behaviour. But a high-risk
205	  // finding that no model has seen is NOT shipped as a confirmed breach; it is demoted. The fabricated-hacking
206	  // class dies here even with every provider down.
207	  const _fallback = (reason) => {
208	    let demoted = 0;
209	    for (const f of out) {
210	      // E-272: an observed fact needs no model. It is not demoted when the LLM is down; it was never in doubt.
211	      if (_observedFact(f)) { f.adjudicated = true; f.adjudication = 'observed_fact'; continue; }
212	      f.adjudicated = false;
213	      if (_highRisk(f)) { f.state = 'NEEDS_REVIEW'; f.adjudication = 'unadjudicated_high_risk'; demoted++; }
214	    }
215	    return { findings: out, report: { ran: false, reason, total: out.length, demoted_high_risk: demoted, dropped: 0 } };
216	  };
217	  if (!gateLLM || (opts && opts.disabled)) return _fallback(gateLLM ? 'disabled' : 'gate_unavailable');
218	
219	  const deadline = Date.now() + Number((opts && opts.deadline_ms) || 60000);
220	  const report = { ran: true, total: out.length, breach: 0, no_breach: 0, insufficient: 0, unadjudicated: 0, dropped: 0, batches: [] };
221	
222	  // E-272: observed facts are ring-fenced BEFORE batching. They are never shown to the model, so it can never
223	  // "insufficient" away a cookie it structurally cannot see.
224	  let observed = 0;
225	  for (const f of out) {
226	    if (_observedFact(f)) { f.adjudicated = true; f.adjudication = 'observed_fact'; observed++; }
227	  }
228	  report.observed_fact = observed;
229	  const judgeable = out.filter((f) => !_observedFact(f));
230	  report.total = judgeable.length;
231	
232	  for (let start = 0; start < judgeable.length; start += BATCH) {
233	    const batch = judgeable.slice(start, start + BATCH);
234	    const briefs = batch.map((f, i) => _brief(f, i));
235	    // E-255: retrieve the REAL statute text for every framework in this batch, so the model rules against the law
236	    // as enacted rather than against our own description column.
237	    const statutes = _statuteFor(batch.map((f) => f.framework || f.framework_short));
238	
239	    let g = null;
240	    if (Date.now() < deadline) {
241	      try {
242	        g = await gateLLM({
243	          role: 'extract', system: _system(), prompt: _prompt(ctx, briefs, statutes), rubric: _rubric(briefs, batch),
244	          threshold: 7, max_attempts: 3, max_tokens: 900, temperature: 0,
245	          scan_id: String(ctx.domain || '') + ':adjudicate:' + start,
246	          deadline_ms: Math.max(8000, deadline - Date.now()),
247	        });
248	      } catch (_e) { g = null; }
249	    } else { report.timed_out = true; }
250	
251	    if (!g || !g.ok || !g.out || !Array.isArray(g.out.verdicts)) {
252	      // This batch could not be adjudicated. Leave it exactly as the regex produced it (no regression), but demote
253	      // the dangerous ones so an unreviewed P0 can never be presented as a confirmed breach.
254	      for (const f of batch) { f.adjudicated = false; if (_highRisk(f)) { f.state = 'NEEDS_REVIEW'; f.adjudication = 'unadjudicated_high_risk'; } }
255	      report.unadjudicated += batch.length;
256	      report.batches.push({ start, ok: false, score: (g && g.score) || 0, why: (g && g.deficiencies) || ['no_answer'] });
257	      continue;
258	    }
259	
260	    for (const v of g.out.verdicts) {
261	      const f = batch[Number(v && v.id)];
262	      if (!f) continue;
263	      const verdict = String((v && v.verdict) || '').toLowerCase();
264	      f.adjudicated = true;
265	      f.adjudication = verdict;
266	      f.adjudication_reason = String((v && v.reason) || '').slice(0, 120);
267	      if (verdict === 'no_breach') {
268	        f._drop = true;                                   // FALSE POSITIVE. It never reaches the client.
269	        f.adjudication_disproof = String((v && v.disproof) || '').slice(0, 200);
270	        report.no_breach++;
271	      } else if (verdict === 'insufficient') {
272	        f.state = 'NEEDS_REVIEW';                         // not a breach, and not a clearance either
273	        report.insufficient++;
274	      } else {
275	        report.breach++;                                  // an ADJUDICATED breach. This is what ships.
276	      }
277	    }
278	    report.batches.push({ start, ok: true, score: g.score, attempts: g.attempts, provider: g.provider });
279	  }
280	
281	  const kept = out.filter((f) => !f._drop);
282	  for (const f of kept) delete f._drop;
283	  report.dropped = out.length - kept.length;
284	  return { findings: kept, report };
285	}
286	
287	module.exports = { adjudicateBreaches, _highRisk, _rubric, _brief, _prompt, _system, _statuteFor };
