1	'use strict';
2	// evidence/browser/observe.js - the PECR pre-consent OBSERVATION lane (P3 Wave-1c).
3	//
4	// WHAT THIS SEES THAT HTML CANNOT (caution.md C-039): the PECR reg.6 breach is not in the page
5	// source, it is in BEHAVIOUR - non-essential cookies written, and tracker requests fired, on first
6	// load with NOTHING clicked. This lane loads a page in a fresh browser, touches nothing, records the
7	// cookies + tracker network events that appear BEFORE any consent interaction, then accepts consent
8	// and captures again for the pre/post diff. A non-essential cookie/tracker present pre-consent is an
9	// observed breach candidate carrying the captured network event as its deterministic artifact
10	// (Constitution Rule 3). This module only OBSERVES; the breach lane (P3 Wave 2) adjudicates.
11	//
12	// FOUR structural safeguards this file is built around:
13	//   1. DEADLINE (C-040 / Rule 9): ONE outer Promise.race wraps launch -> observe -> close. The 752s
14	//      hostage incident is structurally impossible here: observe() cannot outlast deadlineMs + a
15	//      bounded force-close, whatever the browser does. Proven by observe.test.js's hanging-fake test
16	//      and the p3-browser-deadline calibration fixture.
17	//   2. OPTIONAL DEPENDENCY (C-041): Playwright is NOT a package.json dependency. It is resolved
18	//      lazily via an injected launchBrowser factory (or the lazy adapter). When unavailable, the lane
19	//      records lane:{ran:false, reason:'playwright-unavailable'} LOUDLY - never a silent nothing,
20	//      never a throw that kills a mint.
21	//   3. LINK HEALTH (C-042): a found consent/cookie-policy control is health-checked via an injected
22	//      fetch; a broken control is itself a finding (kind:'consent_control_broken').
23	//   4. LICENCE-CLEAN ORACLE (C-043): classification uses evidence/browser/oracle.js, 100% own-authored
24	//      (no NC/AGPL/ShareAlike data); its licence provenance is recorded on lane.oracle.
25	//
26	// TESTABILITY: observe() never touches a real browser or network directly. It drives an injected
27	// `launchBrowser` factory that returns a browser conforming to the small contract documented in
28	// playwright-adapter.js. node:test drives the ENTIRE logic with a scripted FAKE browser; no real
29	// Chromium runs in tests or CI (the acceptance-spec rule: live-fetch paths are dependency-injected).
30	
31	const { raceWithDeadline } = require('./deadline');
32	const { resolvePlaywrightLauncher } = require('./playwright-adapter');
33	const { isTrackerHost, classifyCookie, oracleMeta } = require('./oracle');
34	// HOST is a one-door fact (Rule 1): a hostname is read through the single parsed-host door in
35	// tools/lib/safe-fetch.js, never re-derived here and never substring-matched (GAPS host-substring).
36	const { hostOf: safeHostOf } = require('../../tools/lib/safe-fetch');
37	
38	// Every budget below is a CAP, never a floor (Rule 8): the outer race takes whichever settles first.
39	const DEFAULT_DEADLINE_MS = 45000; // total launch->close ceiling; well under the 120s mint budget
40	const DEFAULT_SETTLE_MS = 3000;    // wait for on-load tags to fire and drop cookies (cap)
41	const DEFAULT_CLOSE_MS = 5000;     // force-close ceiling
42	const DEFAULT_LINK_MS = 8000;      // consent-control link-health fetch ceiling
43	
44	// ── option normalisation ───────────────────────────────────────────────────────────────────────
45	
46	function numOr(v, d) { return Number.isFinite(v) ? v : d; }
47	function numOrNull(v) { const n = Number(v); return Number.isFinite(n) ? n : null; }
48	
49	function normaliseOpts(opts) {
50	  const o = opts || {};
51	  return {
52	    deadlineMs: numOr(o.deadlineMs, DEFAULT_DEADLINE_MS),
53	    settleMs: numOr(o.settleMs, DEFAULT_SETTLE_MS),
54	    closeMs: numOr(o.closeMs, DEFAULT_CLOSE_MS),
55	    linkMs: numOr(o.linkMs, DEFAULT_LINK_MS),
56	    now: typeof o.now === 'function' ? o.now : Date.now,
57	    launchBrowser: o.launchBrowser,
58	    fetchLink: o.fetchLink,
59	    oracle: o.oracle || { isTrackerHost, classifyCookie, oracleMeta },
60	  };
61	}
62	
63	// ── oracle indirection (an injected oracle overrides the module's own; both are licence-clean) ───
64	
65	function oracleMetaOf(cfg) {
66	  const o = cfg.oracle;
67	  return (o && typeof o.oracleMeta === 'function') ? o.oracleMeta() : oracleMeta();
68	}
69	function classify(cfg, cookie) {
70	  const o = cfg.oracle;
71	  return (o && typeof o.classifyCookie === 'function') ? o.classifyCookie(cookie) : classifyCookie(cookie);
72	}
73	function trackerHost(cfg, host) {
74	  const o = cfg.oracle;
75	  return (o && typeof o.isTrackerHost === 'function') ? o.isTrackerHost(host) : isTrackerHost(host);
76	}
77	
78	// ── lane result builders (every non-ran outcome is RECORDED, never silent - C-041/Rule 4) ────────
79	
80	function unknownControl() { return { found: false, healthy: null, url: null }; }
81	
82	function lanePlaywrightUnavailable(cfg) {
83	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'playwright-unavailable', oracle: oracleMetaOf(cfg) } };
84	}
85	function laneDeadline(elapsed, cfg) {
86	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'deadline', elapsedMs: elapsed, oracle: oracleMetaOf(cfg) } };
87	}
88	function laneError(err, elapsed, cfg) {
89	  const message = String((err && err.message) || err).slice(0, 200);
90	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'error', message, elapsedMs: elapsed, oracle: oracleMetaOf(cfg) } };
91	}
92	function laneRan(observed, consentControl, diff, cfg) {
93	  return { observed, consentControl, lane: { ran: true, reason: null, diff, oracle: oracleMetaOf(cfg) } };
94	}
95	
96	// ── host + cookie helpers ────────────────────────────────────────────────────────────────────────
97	
98	function expiryDays(expires, nowMs) {
99	  const e = Number(expires);
100	  if (!Number.isFinite(e) || e <= 0) return null;
101	  return Math.round((e * 1000 - nowMs) / 86400000);
102	}
103	
104	function nonEssentialCookies(cookies, cfg) {
105	  const out = [];
106	  for (const cookie of cookies || []) {
107	    const cls = classify(cfg, cookie);
108	    if (cls.verdict === 'non_essential') out.push({ cookie, cls });
109	  }
110	  return out;
111	}
112	
113	function uniqueHosts(trackers) {
114	  const seen = new Set();
115	  const out = [];
116	  for (const ev of trackers || []) {
117	    if (ev && ev.host && !seen.has(ev.host)) { seen.add(ev.host); out.push(ev.host); }
118	  }
119	  return out;
120	}
121	
122	function firstTrackerForHost(trackers, host) {
123	  for (const ev of trackers || []) {
124	    if (ev && ev.host === host) return ev;
125	  }
126	  return null;
127	}
128	
129	function isTrackerEvent(ev, cfg) {
