214	// Self-test: prove, in memory, that validate() can see each violation kind it exists to catch.
215	// A checker that cannot see its own disease reports every clean run unearned (caution.md C-149).
216	function selfTest() {
217	  const exists = SELF_TEST_GATE_EXISTS;
218	  const cases = SELF_TEST_CASES;
219	  const fails = [];
220	  for (const c of cases) {
221	    const got = validate(c.doc, exists).violations.map((v) => v.kind).sort();
222	    const want = c.wantKinds.slice().sort();
223	    if (JSON.stringify(got) !== JSON.stringify(want)) fails.push(c.name + ': want [' + want + '] got [' + got + ']');
224	  }
225	  return { pass: fails.length === 0, detail: fails.join('; ') || 'all ' + cases.length + ' cases correct' };
226	}
227	
228	function toFindings(violations) {
229	  return violations.map((v) => ({
230	    tool: NAME,
231	    ruleId: 'history-regression:' + v.kind,
232	    file: 'docs/failure-ledger/crossref.json',
233	    startLine: 1,
234	    endLine: 1,
235	    level: 'error',
236	    message: '[' + v.class + '] ' + v.detail,
237	  }));
238	}
239	
240	function loadDoc(p) {
241	  return JSON.parse(fs.readFileSync(p, 'utf8'));
242	}
243	
244	// abortIfSelfTestFails() -> run the in-memory self-test and exit 2 (a broken tool) if the checker
245	// cannot see the class it exists to catch. Every clean run after a failed self-test is unearned.
246	function abortIfSelfTestFails() {
247	  const st = selfTest();
248	  if (st.pass) return;
249	  console.error(NAME + ' SELF-TEST FAILED: ' + st.detail);
250	  console.error('The checker cannot see the class it exists to catch. Every clean run it reports is unearned.');
251	  process.exit(2);
252	}
253	
254	// runCalibration(writeJson) -> --calibrate: validate the seeded broken fixture and REQUIRE it trips
255	// exactly the planted defect (guarded-gate-missing) and only that. Never returns (always exits).
256	function runCalibration(writeJson) {
257	  if (!fs.existsSync(FIXTURE)) {
258	    console.error(NAME + ' CALIBRATION FAILED: ' + path.relative(ROOT, FIXTURE) + ' does not exist. There is nothing to earn a zero against.');
259	    process.exit(1);
260	  }
261	  const res = validate(loadDoc(FIXTURE), realGateExists);
262	  writeJson(toFindings(res.violations));
263	  const kinds = res.violations.map((v) => v.kind).sort();
264	  // The fixture seeds EXACTLY one planted defect: a status=guarded class pointing at a gate file
265	  // that does not exist (guarded-gate-missing), plus a control clean class. Assert the checker
266	  // catches precisely that kind - "any violation > 0" would let a partially-broken checker earn a
267	  // green by tripping on some unrelated defect while missing the seeded one (CR).
268	  const WANT = ['guarded-gate-missing'];
269	  console.log('  ' + NAME + ' calibration: ' + res.violations.length + ' seeded violation(s) caught in the broken fixture');
270	  for (const v of res.violations) console.log('    CAUGHT [' + v.kind + '] ' + v.class + ': ' + v.detail);
271	  if (JSON.stringify(kinds) !== JSON.stringify(WANT)) {
272	    console.error(NAME + ' CALIBRATION FAILED: expected exactly [' + WANT.join(', ') + '] on the seeded fixture, got [' + kinds.join(', ') + ']. The fixture must trip its planted defect and only that.');
273	    process.exit(1);
274	  }
275	  process.exit(0);
276	}
277	
278	// printDeferred(deferred) -> the honest phase-owned gap report: historical classes not yet guarded,
279	// printed loudly every run (they are visible by design, never a silent hole) but not a failure.
280	function printDeferred(deferred) {
281	  if (!deferred.length) return;
282	  console.log('  ' + deferred.length + ' historical failure class(es) NOT YET GUARDED (visible by design, phase-owned):');
283	  for (const g of deferred.slice().sort((a, b) => a.phase.localeCompare(b.phase))) {
284	    console.log('    GAP  [' + g.phase + '] ' + g.class.padEnd(26) + ' -> ' + g.gate + '  (past severity ' + g.past_severity + ')');
285	  }
286	}
287	
288	// runValidation(writeJson) -> the normal run: validate the committed crossref, report guarded/gap
289	// counts and any integrity violations, and exit 1 if any violation exists. Never returns.
290	function runValidation(writeJson) {
291	  if (!fs.existsSync(CROSSREF)) {
292	    console.error(NAME + ': ' + path.relative(ROOT, CROSSREF) + ' does not exist. Build it with `npm run history:build`.');
293	    process.exit(1);
294	  }
295	  const res = validate(loadDoc(CROSSREF), realGateExists);
296	  writeJson(toFindings(res.violations));
297	
298	  console.log('  ' + NAME + ': ' + res.guarded + ' guarded classes, ' + res.gap + ' gap classes, ' + res.violations.length + ' integrity violation(s) (self-test: earned)');
299	  printDeferred(res.deferred);
300	  for (const v of res.violations) console.error('  VIOLATION [' + v.kind + '] ' + v.class + ': ' + v.detail);
301	  process.exit(res.violations.length > 0 ? 1 : 0);
302	}
303	
304	function main() {
305	  const { calibrate, writeJson } = parseGateArgs(process.argv);
306	  abortIfSelfTestFails();
307	  if (calibrate) return runCalibration(writeJson);
308	  return runValidation(writeJson);
309	}
310	
311	if (require.main === module) main();
312	module.exports = { validate, selfTest, toFindings, realGateExists };
