1	#!/usr/bin/env node
2	'use strict';
3	/**
4	 * THE LOCAL ANALYSERS -> the one entry point.
5	 *
6	 * These encode what THIS engine is; no marketplace app replaces them:
7	 *   reachability   a module unreachable from the mint is dead law. On the old estate, statute-rag.js was
8	 *                  required for months and never called; 13 modules / 691 lines were dead.
9	 *   jscpd          textual clones (optional devDependency; skips loudly when absent).
10	 *   dep-cruiser    orphans + circulars (optional devDependency; skips loudly when absent).
11	 *
12	 * one-door and swallow-gate are their OWN tools (tools/one-door, tools/swallow-gate) and are invoked by
13	 * tools/sweep/run.js, not duplicated here. One door for one-door.
14	 *
15	 * A general-purpose tool finds code defects. These find DOMAIN defects. Neither substitutes for the other.
16	 */
17	const fs = require('fs');
18	const path = require('path');
19	const { execSync } = require('child_process');
20	
21	const { listJsFiles } = require('../lib/fswalk');
22	
23	const ROOT = path.resolve(__dirname, '..', '..');
24	const OUT_DIR = path.join(ROOT, 'tools', 'sweep', 'out', 'sarif');
25	const TMP = path.join(ROOT, 'tools', 'sweep', 'out', 'tmp');
26	
27	// Mint entrypoints of the NEW engine. mint/ is empty in P0; entries are armed the moment the files exist.
28	const ENTRIES = ['mint/worker.js', 'mint/index.js'];
29	const SCAN_DIRS = ['catalogue', 'evidence', 'facts', 'applicability', 'breach', 'llm', 'payload'];
30	// Clone and dependency hygiene also cover the tool fleet itself: the tools eat their own cooking.
31	const HYGIENE_DIRS = [...SCAN_DIRS, 'mint', 'render-proof', 'tools'];
32	const nonEmpty = (dirs) => dirs.filter((d) => listJsFiles(path.join(ROOT, d)).length > 0);
33	
34	const out = [];
35	const add = (o) => out.push(o);
36	const hasBin = (name) => fs.existsSync(path.join(ROOT, 'node_modules', '.bin', name));
37	const runBin = (name, argsStr) => {
38	  try {
39	    return execSync(path.join(ROOT, 'node_modules', '.bin', name) + ' ' + argsStr, { cwd: ROOT, encoding: 'utf8', maxBuffer: 128e6, stdio: ['ignore', 'pipe', 'ignore'] });
40	  } catch (e) {
41	    return (e.stdout || '').toString(); /* FAIL-OPEN: these analysers exit non-zero when they FIND things; their findings are on stdout and are ingested below. */
42	  }
43	};
44	
45	// ── reachability from the mint entrypoints ──────────────────────────────────────────────────────────────────
46	// require() extraction is regex-based here (dependency-free). It over-approximates slightly (a require in a
47	// comment counts) but never under-approximates a live edge, which is the direction that matters: a false
48	// "reachable" is noise, a false "unreachable" would be a lie.
49	function requiresOf(file) {
50	  const src = fs.readFileSync(file, 'utf8');
51	  const specs = [];
52	  const rx = /\brequire\(\s*['"]([^'"]+)['"]\s*\)/g;
53	  let m;
54	  while ((m = rx.exec(src)) !== null) specs.push(m[1]);
55	  return specs;
56	}
57	
58	function resolveSpec(from, spec) {
59	  if (!spec.startsWith('.')) return null;
60	  const base = path.resolve(path.dirname(from), spec);
61	  for (const c of [base, base + '.js', base + '.cjs', path.join(base, 'index.js')]) {
62	    if (fs.existsSync(c) && fs.statSync(c).isFile()) return c;
63	  }
64	  return null;
65	}
66	
67	function reachability() {
68	  const entries = ENTRIES.map((e) => path.join(ROOT, e)).filter((p) => fs.existsSync(p));
69	  if (entries.length === 0) {
70	    console.log('  reachability: SKIPPED (no mint entrypoint exists yet: ' + ENTRIES.join(', ') + '). Armed the moment one lands.');
71	    return 0;
72	  }
73	  const reach = new Set();
74	  const walk = (f) => {
75	    if (reach.has(f)) return;
76	    reach.add(f);
77	    for (const s of requiresOf(f)) { const r = resolveSpec(f, s); if (r) walk(r); }
78	  };
79	  entries.forEach(walk);
80	
81	  const dormant = fs.existsSync(path.join(ROOT, 'DORMANT.md')) ? fs.readFileSync(path.join(ROOT, 'DORMANT.md'), 'utf8') : '';
82	  const declared = new Set([...dormant.matchAll(/^\|\s*`([^`]+)`\s*\|/gm)].map((m) => m[1].trim()));
83	
84	  for (const dir of SCAN_DIRS) {
85	    for (const p of listJsFiles(path.join(ROOT, dir), { skipTests: true })) {
86	      if (reach.has(p)) continue;
87	      const rel = path.relative(ROOT, p).replace(/\\/g, '/');
88	      if (declared.has(rel)) continue;
89	      add({
90	        tool: 'reachability', ruleId: 'unreachable-from-mint', file: rel, startLine: 1, level: 'error',
91	        message: 'UNREACHABLE from any mint entrypoint and NOT declared in DORMANT.md. A module unreachable from the mint is dead law: reachable-or-DORMANT is constitutional.',
92	        snippet: 'module ' + rel + ' unreachable',
93	      });
94	    }
95	  }
96	  return reach.size;
97	}
98	
99	// ── jscpd: textual clones ───────────────────────────────────────────────────────────────────────────────────
100	function clones() {
101	  if (!hasBin('jscpd')) { console.log('  jscpd: SKIPPED (not installed; add jscpd to devDependencies to arm this lane)'); return; }
102	  const targets = nonEmpty(HYGIENE_DIRS);
103	  if (targets.length === 0) { console.log('  jscpd: nothing to scan yet'); return; }
104	  fs.mkdirSync(TMP, { recursive: true });
105	  runBin('jscpd', targets.join(' ') + ' --min-tokens 50 --reporters json --output ' + TMP + ' --silent');
106	  const report = path.join(TMP, 'jscpd-report.json');
107	  if (!fs.existsSync(report)) { console.log('  jscpd: ran but wrote no report (treat as a failed lane, not zero clones)'); return; }
108	  const d = JSON.parse(fs.readFileSync(report, 'utf8'));
109	  for (const c of (d.duplicates || [])) {
110	    if (c.firstFile.name === c.secondFile.name) continue;
111	    // NO MINIMUM. Filtering clones below N lines and calling it boilerplate is deciding what you are allowed
112	    // to see. Every clone is reported; the reader decides what is noise.
113	    add({
114	      tool: 'jscpd', ruleId: 'clone', file: c.firstFile.name.replace(ROOT + '/', ''), startLine: c.firstFile.start,
115	      endLine: c.firstFile.end, level: 'warning',
116	      message: c.lines + '-line clone shared with ' + c.secondFile.name.split('/').pop(),
117	      snippet: (c.fragment || '').slice(0, 120),
118	    });
119	  }
120	}
121	
122	// ── dep-cruiser: orphans + circulars ────────────────────────────────────────────────────────────────────────
123	function depcruise() {
124	  if (!hasBin('depcruise')) { console.log('  dependency-cruiser: SKIPPED (not installed; add dependency-cruiser to devDependencies to arm this lane)'); return; }
125	  const targets = nonEmpty(HYGIENE_DIRS);
126	  if (targets.length === 0) { console.log('  dependency-cruiser: nothing to scan yet'); return; }
127	  const j = runBin('depcruise', targets.join(' ') + ' --output-type json --no-config');
128	  let d;
129	  try { d = JSON.parse(j); }
130	  catch (e) { console.error('  dependency-cruiser: output not parseable, lane treated as FAILED not zero (' + e.message + ')'); return; }
131	  for (const m of (d.modules || [])) {
132	    if (m.orphan) add({ tool: 'dependency-cruiser', ruleId: 'orphan', file: m.source, startLine: 0, level: 'note',
133	      message: 'orphan module: nothing depends on it and it depends on nothing', snippet: m.source });
134	    for (const dep of (m.dependencies || [])) if (dep.circular) add({ tool: 'dependency-cruiser', ruleId: 'circular',
135	      file: m.source, startLine: 0, level: 'warning', message: 'circular dependency via ' + dep.resolved, snippet: m.source });
136	  }
137	}
138	
139	function main() {
140	  const reached = reachability();
141	  clones();
142	  depcruise();
143	  fs.mkdirSync(OUT_DIR, { recursive: true });
144	  fs.writeFileSync(path.join(OUT_DIR, 'local.local.json'), JSON.stringify(out, null, 2));
145	  console.log('  reachable from the mint entrypoints: ' + reached + ' modules');
146	  console.log('  local findings: ' + out.length);
147	  const byTool = {};
148	  for (const f of out) byTool[f.tool] = (byTool[f.tool] || 0) + 1;
149	  console.log('  ' + JSON.stringify(byTool));
150	}
151	
152	if (require.main === module) main();
153	module.exports = { requiresOf, resolveSpec };
