21	  assert.equal(r.timedOut, true);
22	  assert.equal(typeof r.elapsed, 'number');
23	});
24	
25	test('raceWithDeadline: STRUCTURAL PROOF - a never-resolving promise resolves the race in bounded wall time', async () => {
26	  const started = Date.now();
27	  const r = await raceWithDeadline(hang(), 30);
28	  const wall = Date.now() - started;
29	  assert.equal(r.timedOut, true);
30	  // The whole point of C-040: the hang cannot extend the wall clock arbitrarily. 30ms cap, generous
31	  // slack for a loaded CI runner, but nowhere near the 752s class this primitive exists to forbid.
32	  assert.ok(wall < 2000, 'raced far past the deadline (' + wall + 'ms) - the hang was NOT bounded');
33	});
